using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker(reorderThreshold: 10);
    }

    #region GetStockLevel

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-999"));
    }

    [TestMethod]
    public void GetStockLevel_AfterAddStock_ReturnsCorrectLevel()
    {
        _tracker.AddStock("SKU-A", 25);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-A"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GetStockLevel_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _tracker.GetStockLevel(sku!));
    }

    #endregion

    #region AddStock

    [TestMethod]
    public void AddStock_NewSku_SetsStockLevel()
    {
        _tracker.AddStock("SKU-B", 50);
        Assert.AreEqual(50, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    public void AddStock_ExistingSku_AccumulatesQuantity()
    {
        _tracker.AddStock("SKU-C", 10);
        _tracker.AddStock("SKU-C", 15);
        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-C"));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100)]
    public void AddStock_NonPositiveQuantity_Throws(int quantity)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.AddStock("SKU-D", quantity));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void AddStock_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _tracker.AddStock(sku!, 5));
    }

    #endregion

    #region RemoveStock

    [TestMethod]
    public void RemoveStock_SufficientStock_DecreasesLevel()
    {
        _tracker.AddStock("SKU-E", 30);
        _tracker.RemoveStock("SKU-E", 12);
        Assert.AreEqual(18, _tracker.GetStockLevel("SKU-E"));
    }

    [TestMethod]
    public void RemoveStock_EntireStock_LeavesZero()
    {
        _tracker.AddStock("SKU-F", 20);
        _tracker.RemoveStock("SKU-F", 20);
        Assert.AreEqual(0, _tracker.GetStockLevel("SKU-F"));
    }

    [TestMethod]
    public void RemoveStock_InsufficientStock_Throws()
    {
        _tracker.AddStock("SKU-G", 5);
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-G", 10));
    }

    [TestMethod]
    public void RemoveStock_FromUnknownSku_Throws()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _tracker.RemoveStock("SKU-MISSING", 1));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-5)]
    public void RemoveStock_NonPositiveQuantity_Throws(int quantity)
    {
        _tracker.AddStock("SKU-H", 10);
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _tracker.RemoveStock("SKU-H", quantity));
    }

    #endregion

    #region NeedsReorder

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-I", 5);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-I"));
    }

    [TestMethod]
    public void NeedsReorder_StockAtThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-J", 10);
        Assert.IsTrue(_tracker.NeedsReorder("SKU-J"));
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-K", 11);
        Assert.IsFalse(_tracker.NeedsReorder("SKU-K"));
    }

    [TestMethod]
    public void NeedsReorder_UnknownSku_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("SKU-NEW"));
    }

    [TestMethod]
    public void NeedsReorder_CustomThreshold_UsesConfiguredValue()
    {
        var tracker = new InventoryTracker(reorderThreshold: 50);
        tracker.AddStock("SKU-L", 45);
        Assert.IsTrue(tracker.NeedsReorder("SKU-L"));

        tracker.AddStock("SKU-L", 10); // now 55
        Assert.IsFalse(tracker.NeedsReorder("SKU-L"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void NeedsReorder_InvalidSku_Throws(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(() => _tracker.NeedsReorder(sku!));
    }

    #endregion

    #region TransferTo (Warehouse Transfers)

    [TestMethod]
    public void TransferTo_ValidTransfer_MovesStockBetweenTrackers()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();

        source.AddStock("SKU-M", 100);
        source.TransferTo(destination, "SKU-M", 40);

        Assert.AreEqual(60, source.GetStockLevel("SKU-M"));
        Assert.AreEqual(40, destination.GetStockLevel("SKU-M"));
    }

    [TestMethod]
    public void TransferTo_EntireStock_EmptiesSource()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();

        source.AddStock("SKU-N", 30);
        source.TransferTo(destination, "SKU-N", 30);

        Assert.AreEqual(0, source.GetStockLevel("SKU-N"));
        Assert.AreEqual(30, destination.GetStockLevel("SKU-N"));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_Throws()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();

        source.AddStock("SKU-O", 10);
        Assert.ThrowsException<InvalidOperationException>(
            () => source.TransferTo(destination, "SKU-O", 20));
    }

    [TestMethod]
    public void TransferTo_InsufficientStock_DoesNotModifyDestination()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();

        source.AddStock("SKU-P", 5);
        destination.AddStock("SKU-P", 10);

        try { source.TransferTo(destination, "SKU-P", 20); }
        catch (InvalidOperationException) { }

        // Destination should remain unchanged on failed transfer
        Assert.AreEqual(10, destination.GetStockLevel("SKU-P"));
    }

    [TestMethod]
    public void TransferTo_NullDestination_Throws()
    {
        _tracker.AddStock("SKU-Q", 10);
        Assert.ThrowsException<ArgumentNullException>(
            () => _tracker.TransferTo(null!, "SKU-Q", 5));
    }

    [TestMethod]
    public void TransferTo_AccumulatesInDestination()
    {
        var source = new InventoryTracker();
        var destination = new InventoryTracker();

        destination.AddStock("SKU-R", 20);
        source.AddStock("SKU-R", 50);
        source.TransferTo(destination, "SKU-R", 15);

        Assert.AreEqual(35, destination.GetStockLevel("SKU-R"));
    }

    #endregion

    #region Constructor

    [TestMethod]
    public void Constructor_NegativeThreshold_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => new InventoryTracker(reorderThreshold: -1));
    }

    [TestMethod]
    public void Constructor_ZeroThreshold_IsValid()
    {
        var tracker = new InventoryTracker(reorderThreshold: 0);
        tracker.AddStock("SKU-S", 1);
        Assert.IsFalse(tracker.NeedsReorder("SKU-S"));
    }

    #endregion
}

